import{_ as a,o,c as r,ag as e,ah as s}from"./chunks/framework.D9bIGSBm.js";const p=JSON.parse('{"title":"终端 TUI 模式","description":"","frontmatter":{},"headers":[],"relativePath":"features/tui-mode.md","filePath":"features/tui-mode.md"}'),l={name:"features/tui-mode.md"};function i(d,t,n,h,c,u){return o(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="终端-tui-模式" tabindex="-1">终端 TUI 模式 <a class="header-anchor" href="#终端-tui-模式" aria-label="Permalink to &quot;终端 TUI 模式&quot;">​</a></h1><p>偏好命令行交互？终端 TUI 模式（v0.9.8 起）可以把一个任务分栏从图形对话切换成 <strong>CLI 原生的终端交互界面</strong>（TUI，即 Claude Code / Codex / OpenCode 自己的命令行对话界面），并<strong>续接同一个会话</strong>——终端里能看到并继续 GUI 中的对话，切回对话视图后终端里新聊的内容也会回读进对话记录（按 CLI 支持程度，见下表）。</p><blockquote><p>相关基础：<a href="/docs/features/multi-pane.html">多任务分屏</a>、<a href="/docs/features/terminal.html">集成终端</a></p></blockquote><p><img src="'+s+'" alt="截图：分栏处于终端模式，嵌入的终端里运行着 Claude Code 交互界面并显示此前的对话，分栏标题栏的切换按钮变为对话图标"></p><div class="tip custom-block"><p class="custom-block-title">与「集成终端」的区别</p><p><a href="/docs/features/terminal.html">集成终端</a>是工作区的 <strong>Shell 终端</strong>（跑构建、装依赖）；终端 TUI 模式则是把<strong>AI 对话本身</strong>换到 CLI 原生界面里继续，两者互不影响。</p></div><hr><h2 id="进入终端模式" tabindex="-1">进入终端模式 <a class="header-anchor" href="#进入终端模式" aria-label="Permalink to &quot;进入终端模式&quot;">​</a></h2><p>点击分栏标题栏右侧的<strong>切换到终端模式</strong>按钮（终端图标，在切分 / 关闭按钮旁）。分栏主区随即嵌入一个终端，按任务当前配置拉起对应 CLI 的交互界面并恢复当前会话；终端模式下同一按钮变为<strong>切换到对话模式</strong>（对话气泡图标）。</p><p>进入有两个前提，不满足时按钮禁用并以悬浮提示说明原因：</p><ul><li><strong>任务空闲</strong>——「任务正在运行，结束后可进入终端」；</li><li><strong>任务已有会话</strong>（至少成功发过一条消息）——「先在对话里发送一条消息，才能进入终端」；草稿分栏不显示此按钮。</li></ul><h3 id="配置随任务注入" tabindex="-1">配置随任务注入 <a class="header-anchor" href="#配置随任务注入" aria-label="Permalink to &quot;配置随任务注入&quot;">​</a></h3><p>进入终端时，任务当前的<strong>模型、思考深度、执行授权、模型供应商（接口地址 / 密钥）、网络代理与自定义环境变量</strong>会等价注入 CLI，终端行为与图形界面保持一致。配置在进入时刻<strong>冻结</strong>——想换模型或权限档，先结束终端会话、改完再进。</p><hr><h2 id="三家-cli-的支持程度" tabindex="-1">三家 CLI 的支持程度 <a class="header-anchor" href="#三家-cli-的支持程度" aria-label="Permalink to &quot;三家 CLI 的支持程度&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>Claude Code</th><th>Codex</th><th>OpenCode</th></tr></thead><tbody><tr><td>按任务配置注入（模型 / 权限 / 供应商 / 代理）</td><td>✅ 完整</td><td>✅ 完整（启动时固定）</td><td>✅ 配置共享</td></tr><tr><td>续接同一会话</td><td>✅ 直接恢复</td><td>✅ 恢复同一线程</td><td>尽力而为（共享会话库）</td></tr><tr><td>终端轮次回读进对话记录</td><td>✅ 支持</td><td>❌ 不回放（模型上下文仍连续）</td><td>尽力而为</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Codex / OpenCode 任务在终端里进行的轮次即使不出现在对话记录里，模型的上下文也是连续的——回到对话视图接着聊，AI 记得终端里发生过什么。</p></div><hr><h2 id="终端模式期间的对话视图" tabindex="-1">终端模式期间的对话视图 <a class="header-anchor" href="#终端模式期间的对话视图" aria-label="Permalink to &quot;终端模式期间的对话视图&quot;">​</a></h2><p>会话被终端模式<strong>持有</strong>期间（包括切走后的等待期），该任务的对话视图变为只读：</p><ul><li>顶部显示横幅「<strong>会话由终端模式持有</strong>」，切走等待自动结束时追加「（终端空闲后将自动结束）」；</li><li>横幅提供两个按钮：<strong>进入终端</strong>（跳回终端视图）与<strong>立即结束</strong>（强制结束终端里的 CLI 进程，需二次确认，正在输出的内容会被中断）；</li><li>输入框与选择器条禁用，发消息、分叉、编辑重跑、回滚、定时执行等入口一并互斥，避免两种形态同时驱动一个会话。</li></ul><hr><h2 id="切走不强杀-空闲后自动收尾" tabindex="-1">切走不强杀：空闲后自动收尾 <a class="header-anchor" href="#切走不强杀-空闲后自动收尾" aria-label="Permalink to &quot;切走不强杀：空闲后自动收尾&quot;">​</a></h2><p>从终端切回对话、或把分栏换绑到其他任务时，终端进程<strong>不会被立刻杀掉</strong>：</p><ol><li>若终端还在输出（AI 正在回复），进程保活继续跑；</li><li>终端输出<strong>持续安静约 10 秒</strong>（视为当前消息已处理完）后，进程自动结束，防止后台进程越积越多；</li><li>自动结束前切回终端视图，会<strong>直接复用原进程与画面</strong>，滚动缓冲不丢；</li><li>进程结束后（自动收尾或你在终端里 <code>/exit</code> 退出），对话历史自动刷新；停留在终端视图时会显示「<strong>终端会话已结束</strong>」覆盖层，可选择<strong>重新进入终端</strong>或<strong>返回对话</strong>。</li></ol><div class="warning custom-block"><p class="custom-block-title">切走前先处理完终端里的待确认项</p><p>「空闲」按终端输出是否安静判定。若终端正<strong>停在权限确认</strong>等待你输入，输出同样是安静的——切走约 10 秒后进程会被自动结束，该轮次作废。切走前请先处理完终端里的待确认操作（横幅会显示终端仍被持有）。</p></div><hr><h2 id="已知限制" tabindex="-1">已知限制 <a class="header-anchor" href="#已知限制" aria-label="Permalink to &quot;已知限制&quot;">​</a></h2><ul><li>使用<strong>中转 / 第三方供应商</strong>的 Codex 任务，终端界面里显示的模型名可能是内部占位名，实际生效模型以任务配置为准。</li><li>个别情况下权限档位会为适配交互模式自动降级，横幅会注明「（权限档已降级适配交互模式）」。</li><li>退出应用、删除任务或工作区时，对应的终端进程会被连带结束，不会残留。</li></ul><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>回到图形界面的工作流——前往 <a href="/docs/features/git.html">Git 集成</a>了解分支管理、变更审查与提交。</p>',31)])])}const m=a(l,[["render",i]]);export{p as __pageData,m as default};
